function solve(s) {
    const n = s.length;
    let maxLen = 0;

    // Helper function to find the longest balanced substring in a given string t
    const findLongestBalancedSubstring = (t) => {
        const lenT = t.length;
        if (lenT === 0) return 0;

        // Prefix sum difference: count('1') - count('0')
        // A substring t[i..j] is balanced if prefixSum[j+1] - prefixSum[i] == 0
        // i.e., prefixSum[j+1] == prefixSum[i]
        const map = new Map();
        map.set(0, -1); // Difference 0 occurs before index 0 (at index -1)
        let currentDiff = 0;
        let maxLength = 0;

        for (let j = 0; j < lenT; j++) {
            currentDiff += (t[j] === '1' ? 1 : -1);

            if (map.has(currentDiff)) {
                const i = map.get(currentDiff);
                maxLength = Math.max(maxLength, j - i);
            } else {
                map.set(currentDiff, j);
            }
        }
        return maxLength;
    };

    // Case 0: No swap (or if all characters are the same)
    maxLen = Math.max(maxLen, findLongestBalancedSubstring(s));

    // Case 1: One swap
    for (let i = 0; i < n; i++) {
        for (let j = i + 1; j < n; j++) {
            // Swap s[i] and s[j]
            const charI = s[i];
            const charJ = s[j];

            // Optimization: only swap if they are different
            if (charI === charJ) continue;

            // Create the new string t
            let t_arr = s.split('');
            t_arr[i] = charJ;
            t_arr[j] = charI;
            const t = t_arr.join('');

            // Find the longest balanced substring in the swapped string t
            const currentMax = findLongestBalancedSubstring(t);
            maxLen = Math.max(maxLen, currentMax);
        }
